@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("initialize", _element, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnUserIdle()
    {
        if (!_isIdle)
        {
            _isIdle = true;
            await OnIdle.InvokeAsync();
        }
    }

    [JSInvokable]
    public async Task OnUserActive()
    {
        if (_isIdle)
        {
            _isIdle = false;
            await OnActive.InvokeAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose");
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

let timer = null;
let dotNetHelper = null;
let element = null;
let timeoutMs = 300000;
let isIdle = false;

const activityEvents = ["mousemove", "keydown", "click", "scroll"];

function resetTimer() {
    if (isIdle) {
        isIdle = false;
        dotNetHelper.invokeMethodAsync("OnUserActive");
    }
    clearTimeout(timer);
    timer = setTimeout(() => {
        isIdle = true;
        dotNetHelper.invokeMethodAsync("OnUserIdle");
    }, timeoutMs);
}

function handleActivity() {
    resetTimer();
}

export function initialize(el, helper, timeout) {
    element = el;
    dotNetHelper = helper;
    timeoutMs = timeout;
    isIdle = false;

    activityEvents.forEach(event => {
        element.addEventListener(event, handleActivity, { passive: true });
    });

    resetTimer();
}

export function dispose() {
    clearTimeout(timer);
    timer = null;

    if (element) {
        activityEvents.forEach(event => {
            element.removeEventListener(event, handleActivity);
        });
    }

    element = null;
    dotNetHelper = null;
}

